import{_ as i,o as r,c as a,ag as t}from"./chunks/framework.ePeAWSvT.js";const p=JSON.parse('{"title":"COURS : L’ANGINE DE POITRINE (ANGOR)","description":"","frontmatter":{},"headers":[],"relativePath":"matieres/sante/cours/ANGOR-cardio.md","filePath":"matieres/sante/cours/ANGOR-cardio.md"}'),n={name:"matieres/sante/cours/ANGOR-cardio.md"};function s(l,e,o,u,d,c){return r(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="cours-l-angine-de-poitrine-angor" tabindex="-1">COURS : L’ANGINE DE POITRINE (ANGOR) <a class="header-anchor" href="#cours-l-angine-de-poitrine-angor" aria-label="Permalink to &quot;COURS : L’ANGINE DE POITRINE (ANGOR)&quot;">​</a></h1><h2 id="_1️⃣-definition" tabindex="-1">1️⃣ Définition <a class="header-anchor" href="#_1️⃣-definition" aria-label="Permalink to &quot;1️⃣ Définition&quot;">​</a></h2><p>L’angine de poitrine, appelée aussi <strong>angor</strong>, est une <strong>douleur thoracique causée par une diminution de l’apport en oxygène au muscle cardiaque (myocarde)</strong>.</p><p>Elle survient lorsque les <strong>artères coronaires sont rétrécies</strong> et ne peuvent pas fournir suffisamment de sang au cœur.</p><p>👉 La cause la plus fréquente est <strong>l’athérosclérose des artères coronaires</strong>.</p><hr><h2 id="_2️⃣-physiopathologie" tabindex="-1">2️⃣ Physiopathologie <a class="header-anchor" href="#_2️⃣-physiopathologie" aria-label="Permalink to &quot;2️⃣ Physiopathologie&quot;">​</a></h2><p>Le cœur a besoin d’un apport constant en <strong>oxygène et en nutriments</strong>.</p><p>Lorsque les <strong>artères coronaires sont rétrécies</strong>, le débit sanguin diminue.</p><p>📌 Pendant un effort ou un stress, les besoins du cœur augmentent, mais les artères ne peuvent pas fournir suffisamment de sang.</p><p>➡️ Cela provoque <strong>une ischémie myocardique</strong>, responsable de la douleur.</p><hr><h2 id="_3️⃣-types-d-angine-de-poitrine" tabindex="-1">3️⃣ Types d’angine de poitrine <a class="header-anchor" href="#_3️⃣-types-d-angine-de-poitrine" aria-label="Permalink to &quot;3️⃣ Types d’angine de poitrine&quot;">​</a></h2><h3 id="🔹-angor-stable" tabindex="-1">🔹 Angor stable <a class="header-anchor" href="#🔹-angor-stable" aria-label="Permalink to &quot;🔹 Angor stable&quot;">​</a></h3><ul><li>Survient lors d’un <strong>effort physique ou d’un stress</strong></li><li>Douleur <strong>prévisible</strong></li><li>Disparaît avec <strong>le repos ou la trinitrine</strong></li></ul><hr><h3 id="🔹-angor-instable" tabindex="-1">🔹 Angor instable <a class="header-anchor" href="#🔹-angor-instable" aria-label="Permalink to &quot;🔹 Angor instable&quot;">​</a></h3><ul><li>Douleur <strong>plus intense</strong></li><li>Survient <strong>au repos ou pour un effort minimal</strong></li><li>Durée <strong>plus longue</strong></li><li>Peut annoncer un <strong>infarctus du myocarde</strong></li></ul><p>⚠️ C’est une <strong>urgence médicale</strong>.</p><hr><h3 id="🔹-angor-de-prinzmetal-angor-vasospastique" tabindex="-1">🔹 Angor de Prinzmetal (angor vasospastique) <a class="header-anchor" href="#🔹-angor-de-prinzmetal-angor-vasospastique" aria-label="Permalink to &quot;🔹 Angor de Prinzmetal (angor vasospastique)&quot;">​</a></h3><ul><li>Causé par un <strong>spasme des artères coronaires</strong></li><li>Survient souvent <strong>au repos</strong></li><li>Généralement <strong>la nuit ou tôt le matin</strong></li></ul><hr><h2 id="_4️⃣-facteurs-de-risque" tabindex="-1">4️⃣ Facteurs de risque <a class="header-anchor" href="#_4️⃣-facteurs-de-risque" aria-label="Permalink to &quot;4️⃣ Facteurs de risque&quot;">​</a></h2><p>Plusieurs facteurs favorisent l’apparition de l’angine de poitrine :</p><ul><li>Hypertension artérielle</li><li>Diabète</li><li>Hypercholestérolémie</li><li>Tabagisme</li><li>Obésité</li><li>Sédentarité</li><li>Stress</li><li>Antécédents familiaux de maladies cardiovasculaires</li><li>Âge avancé</li></ul><hr><h2 id="_5️⃣-signes-et-symptomes" tabindex="-1">5️⃣ Signes et symptômes <a class="header-anchor" href="#_5️⃣-signes-et-symptomes" aria-label="Permalink to &quot;5️⃣ Signes et symptômes&quot;">​</a></h2><p>La manifestation principale est la <strong>douleur thoracique</strong>.</p><p>Caractéristiques :</p><ul><li>Douleur <strong>oppressive ou constrictive</strong></li><li>Localisée <strong>derrière le sternum</strong></li><li>Peut irradier vers : <ul><li>le bras gauche</li><li>la mâchoire</li><li>le cou</li><li>le dos</li><li>l’épaule</li></ul></li></ul><p>Autres symptômes possibles :</p><ul><li>Essoufflement (dyspnée)</li><li>Sueurs</li><li>Nausées</li><li>Fatigue</li><li>Anxiété</li></ul><hr><h2 id="_6️⃣-diagnostic" tabindex="-1">6️⃣ Diagnostic <a class="header-anchor" href="#_6️⃣-diagnostic" aria-label="Permalink to &quot;6️⃣ Diagnostic&quot;">​</a></h2><p>Le diagnostic repose sur :</p><h3 id="🩺-examen-clinique" tabindex="-1">🩺 Examen clinique <a class="header-anchor" href="#🩺-examen-clinique" aria-label="Permalink to &quot;🩺 Examen clinique&quot;">​</a></h3><ul><li>Interrogatoire du patient</li><li>Évaluation des facteurs de risque</li></ul><h3 id="📊-examens-complementaires" tabindex="-1">📊 Examens complémentaires <a class="header-anchor" href="#📊-examens-complementaires" aria-label="Permalink to &quot;📊 Examens complémentaires&quot;">​</a></h3><ul><li><strong>Électrocardiogramme (ECG)</strong></li><li><strong>Test d’effort</strong></li><li><strong>Dosage des enzymes cardiaques</strong></li><li><strong>Échocardiographie</strong></li><li><strong>Coronarographie</strong></li></ul><hr><h2 id="_7️⃣-complications" tabindex="-1">7️⃣ Complications <a class="header-anchor" href="#_7️⃣-complications" aria-label="Permalink to &quot;7️⃣ Complications&quot;">​</a></h2><p>Si l’angine de poitrine n’est pas prise en charge, elle peut évoluer vers :</p><ul><li><strong>Infarctus du myocarde</strong></li><li><strong>Troubles du rythme cardiaque</strong></li><li><strong>Insuffisance cardiaque</strong></li><li><strong>Mort subite</strong></li></ul><hr><h2 id="_8️⃣-traitement" tabindex="-1">8️⃣ Traitement <a class="header-anchor" href="#_8️⃣-traitement" aria-label="Permalink to &quot;8️⃣ Traitement&quot;">​</a></h2><h3 id="🥗-mesures-hygieno-dietetiques" tabindex="-1">🥗 Mesures hygiéno-diététiques <a class="header-anchor" href="#🥗-mesures-hygieno-dietetiques" aria-label="Permalink to &quot;🥗 Mesures hygiéno-diététiques&quot;">​</a></h3><ul><li>Arrêt du tabac</li><li>Alimentation équilibrée</li><li>Réduction du cholestérol</li><li>Activité physique adaptée</li><li>Contrôle du poids</li><li>Gestion du stress</li></ul><hr><h3 id="💊-traitement-medicamenteux" tabindex="-1">💊 Traitement médicamenteux <a class="header-anchor" href="#💊-traitement-medicamenteux" aria-label="Permalink to &quot;💊 Traitement médicamenteux&quot;">​</a></h3><ul><li><strong>Trinitrine (dérivés nitrés)</strong> : soulage rapidement la douleur</li><li><strong>Bêta-bloquants</strong></li><li><strong>Inhibiteurs calciques</strong></li><li><strong>Antiagrégants plaquettaires (aspirine)</strong></li><li><strong>Statines</strong></li></ul><hr><h3 id="🏥-traitement-interventionnel" tabindex="-1">🏥 Traitement interventionnel <a class="header-anchor" href="#🏥-traitement-interventionnel" aria-label="Permalink to &quot;🏥 Traitement interventionnel&quot;">​</a></h3><p>Dans certains cas :</p><ul><li><strong>Angioplastie coronaire</strong></li><li><strong>Pose de stent</strong></li><li><strong>Pontage coronarien</strong></li></ul><hr><h2 id="_9️⃣-surveillance-du-patient" tabindex="-1">9️⃣ Surveillance du patient <a class="header-anchor" href="#_9️⃣-surveillance-du-patient" aria-label="Permalink to &quot;9️⃣ Surveillance du patient&quot;">​</a></h2><p>La surveillance comprend :</p><ul><li>Évaluation de la <strong>douleur thoracique</strong></li><li>Surveillance de la <strong>pression artérielle</strong></li><li>Surveillance de la <strong>fréquence cardiaque</strong></li><li>Surveillance de la <strong>saturation en oxygène</strong></li><li>Suivi de l’efficacité du traitement</li></ul><hr><h2 id="🔟-role-infirmier-👨‍⚕️👩‍⚕️" tabindex="-1">🔟 Rôle infirmier 👨‍⚕️👩‍⚕️ <a class="header-anchor" href="#🔟-role-infirmier-👨‍⚕️👩‍⚕️" aria-label="Permalink to &quot;🔟 Rôle infirmier 👨‍⚕️👩‍⚕️&quot;">​</a></h2><p>Le rôle infirmier est essentiel dans la prise en charge du patient :</p><ul><li>Identifier rapidement les <strong>douleurs thoraciques</strong></li><li>Surveiller les <strong>signes vitaux</strong></li><li>Administrer les <strong>médicaments prescrits</strong></li><li>Surveiller les effets du traitement</li><li>Éduquer le patient sur les <strong>facteurs de risque</strong></li><li>Informer le patient sur les <strong>signes d’alerte d’un infarctus</strong></li><li>Soutenir le patient et réduire l’anxiété</li></ul>',63)])])}const h=i(n,[["render",s]]);export{p as __pageData,h as default};
